{
  "data": [{
    "type": "osm",
    "queryArea": { "geocodeArea": "Chicago", "areas": ["Loop"] },
    "outputTableName": "table_osm",
    "autoLoadLayers": { "layers": ["buildings"], "dropOsmTable": true }
  }],
  "compute": [{
    "dataRef": "table_osm_buildings",
    "attributes": { "h": "height" },
    "outputColumnName": "height_m",
    "wglsFunction": "if (h <= 0.0) { return 10.0; } return h;"
  }],
  "map": {
    "layerRefs": [{
      "dataRef": "table_osm_buildings",
      "isPick": true,
      "getFnv": "compute.height_m",
      "getFnvType": "quantitative",
      "defaultFnv": 10
    }]
  },
  "plot": {
    "dataRef": "table_osm_buildings",
    "mark": "bar",
    "axis": ["compute.height_m", "@transform"],
    "title": "Chicago Loop building heights",
    "transform": { "preset": "binning-1d", "options": { "bins": 15 } },
    "events": ["brushX"],
    "mapRef": "table_osm_buildings"
  }
}
